package com.examportal.evaluation;

import jakarta.persistence.*;
import lombok.*;

import java.time.LocalDateTime;

/**
 * EvaluationResult - Stores scored output after exam submission.
 * Generated by EvaluationService. One record per attempt.
 * subjectWiseBreakdown: JSON { subjectName: { correct, wrong, unattempted, score, total } }
 * violationSummary: JSON array of violation log entries.
 */
@Entity
@Table(name = "evaluation_results")
@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class EvaluationResult {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, unique = true)
    private Long attemptId;

    private Long studentId;
    private Long examId;

    private Double totalScore;
    private Integer totalQuestions;
    private Integer attempted;
    private Integer correct;
    private Integer wrong;
    private Integer unattempted;

    @Column(columnDefinition = "TEXT")
    private String subjectWiseBreakdown;

    @Column(columnDefinition = "TEXT")
    @Builder.Default
    private String violationSummary = "[]";

    @Column(updatable = false)
    private LocalDateTime evaluatedAt;

    @PrePersist
    protected void onCreate() { evaluatedAt = LocalDateTime.now(); }
}
